impl FromXml for PivotFormat {
    fn from_xml<R: BufRead>(
        reader: &mut Reader<R>,
        start_tag: &BytesStart,
        is_empty: bool,
    ) -> Result<Self, ParseError> {
        #[cfg(feature = "dml-charts")]
        let mut f_idx: Option<Box<CTUnsignedInt>> = None;
        #[cfg(feature = "dml-charts")]
        let mut f_sp_pr = None;
        #[cfg(feature = "dml-charts")]
        let mut f_tx_pr = None;
        #[cfg(feature = "dml-charts")]
        let mut f_marker = None;
        #[cfg(feature = "dml-charts")]
        let mut f_d_lbl = None;
        #[cfg(feature = "dml-charts")]
        let mut f_ext_lst = None;
        #[cfg(feature = "extra-children")]
        let mut extra_children = Vec::new();
        #[cfg(feature = "extra-children")]
        let mut child_idx: usize = 0;

        // Parse child elements
        if !is_empty {
            let mut buf = Vec::new();
            loop {
                match reader.read_event_into(&mut buf)? {
                    Event::Start(e) => {
                        match e.local_name().as_ref() {
                            #[cfg(feature = "dml-charts")]
                            b"idx" => {
                                f_idx = Some(Box::new(CTUnsignedInt::from_xml(reader, &e, false)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"spPr" => {
                                f_sp_pr =
                                    Some(Box::new(CTShapeProperties::from_xml(reader, &e, false)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"txPr" => {
                                f_tx_pr = Some(Box::new(TextBody::from_xml(reader, &e, false)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"marker" => {
                                f_marker =
                                    Some(Box::new(ChartMarker::from_xml(reader, &e, false)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"dLbl" => {
                                f_d_lbl = Some(Box::new(DataLabel::from_xml(reader, &e, false)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"extLst" => {
                                f_ext_lst = Some(Box::new(ChartExtensionList::from_xml(
                                    reader, &e, false,
                                )?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "extra-children")]
                            _ => {
                                // Capture unknown element for roundtrip
                                let elem = RawXmlElement::from_reader(reader, &e)?;
                                extra_children.push(PositionedNode::new(
                                    child_idx,
                                    RawXmlNode::Element(elem),
                                ));
                                child_idx += 1;
                            }
                            #[cfg(not(feature = "extra-children"))]
                            _ => {
                                // Skip unknown element
                                skip_element(reader)?;
                            }
                        }
                    }
                    Event::Empty(e) => {
                        match e.local_name().as_ref() {
                            #[cfg(feature = "dml-charts")]
                            b"idx" => {
                                f_idx = Some(Box::new(CTUnsignedInt::from_xml(reader, &e, true)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"spPr" => {
                                f_sp_pr =
                                    Some(Box::new(CTShapeProperties::from_xml(reader, &e, true)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"txPr" => {
                                f_tx_pr = Some(Box::new(TextBody::from_xml(reader, &e, true)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"marker" => {
                                f_marker = Some(Box::new(ChartMarker::from_xml(reader, &e, true)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"dLbl" => {
                                f_d_lbl = Some(Box::new(DataLabel::from_xml(reader, &e, true)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "dml-charts")]
                            b"extLst" => {
                                f_ext_lst =
                                    Some(Box::new(ChartExtensionList::from_xml(reader, &e, true)?));
                                #[cfg(feature = "extra-children")]
                                {
                                    child_idx += 1;
                                }
                            }
                            #[cfg(feature = "extra-children")]
                            _ => {
                                // Capture unknown empty element for roundtrip
                                let elem = RawXmlElement::from_empty(&e);
                                extra_children.push(PositionedNode::new(
                                    child_idx,
                                    RawXmlNode::Element(elem),
                                ));
                                child_idx += 1;
                            }
                            #[cfg(not(feature = "extra-children"))]
                            _ => {}
                        }
                    }
                    Event::End(_) => break,
                    Event::Eof => break,
                    _ => {}
                }
                buf.clear();
            }
        }

        Ok(Self {
            #[cfg(feature = "dml-charts")]
            idx: f_idx.ok_or_else(|| ParseError::MissingAttribute("idx".to_string()))?,
            #[cfg(feature = "dml-charts")]
            sp_pr: f_sp_pr,
            #[cfg(feature = "dml-charts")]
            tx_pr: f_tx_pr,
            #[cfg(feature = "dml-charts")]
            marker: f_marker,
            #[cfg(feature = "dml-charts")]
            d_lbl: f_d_lbl,
            #[cfg(feature = "dml-charts")]
            ext_lst: f_ext_lst,
            #[cfg(feature = "extra-children")]
            extra_children,
        })
    }
}

